const body = $json.body || $json;

const sourceType = String(body.sourceType || body.type || 'text').toLowerCase();
const value = String(body.value || body.content || body.url || '').trim();
const title = String(body.title || '').trim();
const originalUrl = String(body.originalUrl || body.url || value || '').trim();

function titleFromValue(input, fallback) {
  if (title) return title;
  if (!input) return fallback;
  try {
    const url = new URL(input);
    return url.hostname.replace(/^www\./, '');
  } catch {
    return input.slice(0, 60) || fallback;
  }
}

return [{
  json: {
    sourceType,
    title: titleFromValue(value, 'Untitled Source'),
    value,
    originalUrl: ['website', 'youtube', 'pdf', 'image'].includes(sourceType) ? originalUrl : '',
    extractedText: '',
    summary: '',
    status: 'reading',
    statusMessage: 'Reading source...',
    parserProvider: 'none'
  }
}];

const text = String($json.value || '').replace(/\s+/g, ' ').trim();
const MAX_CHARS = 60000;
const safeText = text.length > MAX_CHARS ? text.slice(0, MAX_CHARS) + '\n\n[Text trimmed for demo token limit.]' : text;

return [{
  json: {
    ...$json,
    extractedText: safeText,
    summary: safeText.length > 280 ? safeText.slice(0, 280) + '...' : safeText,
    status: safeText ? 'ready' : 'failed',
    statusMessage: safeText ? 'Text source is ready.' : 'No text content was provided.',
    parserProvider: 'direct-text'
  }
}];

