    statusMessage: ok ? 'Image extracted using Gemini fallback.' : 'Could not read this image. Try a clearer image or copied text.',
    parserProvider: ok ? 'gemini-vision' : 'image-failed'
  }
}];

return [{
  json: {
    ...$json,
    status: 'failed',
    statusMessage: `Unsupported source type: ${$json.sourceType}`,
    parserProvider: 'unsupported-source-type'
  }
}];

const item = $json;

function cleanText(value) {
  return String(value || '')
    .replace(/\r\n/g, '\n')
    .replace(/\n{4,}/g, '\n\n\n')
    .trim();
}

function compactText(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

const extractedCandidates = [
  item.extractedText,
  item.fullExtractedText,
  item.text,
  item.content,
  item.markdown,
  item.summary,
  item.value
];

const fullExtractedText = cleanText(extractedCandidates.find(value => cleanText(value).length > 0) || '');
const summaryBase = compactText(item.summary || fullExtractedText || item.value);
const summary = summaryBase.length > 700 ? `${summaryBase.slice(0, 700)}...` : summaryBase;

return [{
  json: {
    sourceType: item.sourceType || 'text',
    title: item.title || 'Untitled Source',
    value: item.value || '',
    originalUrl: item.originalUrl || '',
    extractedText: fullExtractedText,
    summary,
    status: item.status || (fullExtractedText ? 'ready' : 'failed'),
    statusMessage: item.statusMessage || (fullExtractedText ? 'Source reader finished.' : 'No readable content was extracted.'),
    parserProvider: item.parserProvider || 'unknown',
    extractionLength: fullExtractedText.length
  }
}];

const item = $json;

function cleanText(value) {
  return String(value || "")
    .replace(/\r\n/g, "\n")
    .replace(/\n{4,}/g, "\n\n")
    .trim();
}

function compactText(value) {
  return String(value || "").replace(/\s+/g, " ").trim();
}

function isGenericTitle(value) {
  const title = compactText(value)
    .toLowerCase()
    .replace(/\.[a-z0-9]+$/i, "");

  if (!title) return true;

  return /^(img|image|screenshot|screen shot|photo|document|scan|untitled|file|upload|source|study source)[-_\s]?\d*/i.test(title);
}

const fullExtractedText = cleanText(
  item.extractedText ||
    item.fullExtractedText ||
    item.text ||
    item.content ||
    item.markdown ||
    item.summary ||
    item.value ||
    "",
);

const excerpt =
  fullExtractedText.length > 12000
    ? `${fullExtractedText.slice(0, 12000)}\n\n[Excerpt only for metadata generation. Keep the original extractedText unchanged in later nodes.]`
    : fullExtractedText;

const existingSummary = compactText(item.summary);

const shouldGenerateMetadata =
  Boolean(fullExtractedText) &&
  (isGenericTitle(item.title) || !existingSummary || existingSummary.length < 180);

const prompt = `PART 1 — ROLE AND GOAL
You are Study Aura's Source Metadata Agent.
Create a clean, student-friendly, presentation-ready source title and a useful study summary.

PART 2 — SOURCE CONTEXT
Source type: ${item.sourceType || "unknown"}
Current title: ${item.title || "Untitled Source"}
Original URL or value: ${item.originalUrl || item.value || ""}
Parser provider: ${item.parserProvider || "unknown"}

Extracted content excerpt:
${excerpt}

PART 3 — OUTPUT CONTRACT
Return ONLY valid JSON.
Do not use markdown fences.
Do not add extra text before or after the JSON.

Schema:
{
  "title": "5 to 9 words, specific, clean, no file extensions, no raw URLs",
  "summary": "4 to 6 complete sentences explaining what this source contains and what students can learn from it.",
  "confidence": "high"
}

Rules:
- Do not use generic names like IMG_1231, screenshot, document, file, upload, source, or untitled.
- If the content is an image description, title the actual subject of the image.
- If the image is educational, explain its learning value in the summary.
- If the content is a PDF/document, title the actual topic, not the filename.
- If the content is a webpage, title the page topic, not the domain.
- If unsure, infer the best educational title from the strongest subject in the excerpt.
- Keep the title professional and demo-ready.
- Keep the summary informative, not too short.
- The summary must be based only on the extracted content excerpt.`;

return [
  {
    json: {
      ...item,
      fullExtractedText,
      extractedText: fullExtractedText,
      metadataExcerpt: excerpt,
      metadataPrompt: prompt,
      shouldGenerateMetadata,
      aiMetadataStatus: shouldGenerateMetadata ? "pending" : "ready",
    },
  },
];

const current = $input.first().json;

const rawOutput =
  current.output ||
  current.text ||
  current.response ||
  current.content ||
  "";

function extractJson(input) {
  const raw = String(input || "").trim();

  if (!raw) return {};

  const cleaned = raw
    .replace(/^```json/i, "")
    .replace(/^```/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch {
    const match = cleaned.match(/\{[\s\S]*\}/);

    if (!match) return {};

    try {
      return JSON.parse(match[0]);
    } catch {
      return {};
    }
  }
}

const parsed = extractJson(rawOutput);

return [
  {
    json: {
      ...current,
      geminiMetadata: {
        title: String(parsed.title || "").trim(),
        summary: String(parsed.summary || "").trim(),
        confidence: String(parsed.confidence || "").trim(),
      },
      metadataProvider: parsed.title
        ? "gemini-title-agent"
        : "gemini-title-agent-failed",
    },
  },
];

const current = $input.first().json;

const rawOutput =
  current.output ||
  current.text ||
  current.response ||
  current.content ||
  "";

function extractJson(input) {
  const raw = String(input || "").trim();

  if (!raw) return {};

  const cleaned = raw
    .replace(/^```json/i, "")
    .replace(/^```/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch {
    const match = cleaned.match(/\{[\s\S]*\}/);

    if (!match) return {};

    try {
      return JSON.parse(match[0]);
    } catch {
      return {};
    }
  }
}

const parsed = extractJson(rawOutput);

return [
  {
    json: {
      ...current,
      groqMetadata: {
        title: String(parsed.title || "").trim(),
        summary: String(parsed.summary || "").trim(),
        confidence: String(parsed.confidence || "").trim(),
      },
      metadataProvider: parsed.title
        ? "groq-title-agent"
        : "groq-title-agent-failed",
    },
  },
];

const current = $input.first().json;

let source = {};
try {
  source = $("Final Response Shape").first().json;
} catch {
  source = {};
}

let prepared = {};
try {
  prepared = $("Prepare AI Metadata Prompt").first().json;
} catch {
  prepared = {};
}

const geminiMetadata =
  current.geminiMetadata ||
  (() => {
    try {
      return $("Normalize Gemini Metadata").first().json.geminiMetadata || {};
    } catch {
      return {};
    }
  })();

const groqMetadata =
  current.groqMetadata ||
  (() => {
    try {
      return $("Normalize Groq Metadata").first().json.groqMetadata || {};
    } catch {
      return {};
    }
  })();

function compactText(value) {
  return String(value || "").replace(/\s+/g, " ").trim();
}

function keepReadableText(value) {
  return String(value || "")
    .replace(/\r\n/g, "\n")
    .replace(/\n{4,}/g, "\n\n")
    .trim();
}

function isBadTitle(value) {
  const title = compactText(value).toLowerCase();

  if (!title) return true;

  return (
    title === "study source" ||
    title === "untitled source" ||
    title === "source" ||
    title === "image" ||
    title === "pdf" ||
    title === "document" ||
    title === "file" ||
    /^img[_\-\s]?\d*/i.test(title) ||
    /^image[_\-\s]?\d*/i.test(title) ||
    /^screenshot[_\-\s]?\d*/i.test(title) ||
    /^screen shot[_\-\s]?\d*/i.test(title) ||
    /^document[_\-\s]?\d*/i.test(title)
  );
}

function makeFallbackTitle(source, prepared) {
  const text = compactText(
    source.summary || source.extractedText || prepared.fullExtractedText || prepared.metadataExcerpt,
  );

  if (text) {
    const firstSentence =
      text
        .split(/[.!?]/)
        .map((part) => compactText(part))
        .find((part) => part.length >= 12 && part.length <= 90) || "";

    if (firstSentence) return firstSentence.slice(0, 70);
  }

  const urlValue = source.originalUrl || prepared.originalUrl || source.value || prepared.value;

  if (urlValue) {
    try {
      const url = new URL(urlValue);
      const rawFileName = decodeURIComponent(url.pathname.split("/").filter(Boolean).pop() || "");

      const fileName = rawFileName
        .replace(/\.[a-z0-9]+$/i, "")
        .replace(/^[a-f0-9-]{12,}-/i, "")
        .replace(/[_-]+/g, " ")
        .trim();

      if (fileName && !isBadTitle(fileName)) return fileName.slice(0, 70);

      return url.hostname.replace(/^www\./, "");
    } catch {}
  }

  return "Study Source";
}

const extractedText = keepReadableText(
  source.extractedText || prepared.fullExtractedText || prepared.extractedText || current.fullExtractedText || current.extractedText || "",
);

const aiTitle = compactText(geminiMetadata.title || groqMetadata.title);
const aiSummary = compactText(geminiMetadata.summary || groqMetadata.summary);
const originalSummary = compactText(source.summary || prepared.summary || current.summary);

const title = !isBadTitle(aiTitle)
  ? aiTitle
  : !isBadTitle(source.title || prepared.title || current.title)
    ? compactText(source.title || prepared.title || current.title)
    : makeFallbackTitle(source, prepared);

const summary =
  aiSummary ||
  originalSummary ||
  (extractedText.length > 900 ? `${extractedText.slice(0, 900)}...` : extractedText) ||
  "No summary was generated for this source.";

return [
  {
    json: {
      sourceType: source.sourceType || prepared.sourceType || current.sourceType || "text",
      title,
      value: source.value || prepared.value || current.value || "",
      originalUrl: source.originalUrl || prepared.originalUrl || current.originalUrl || "",
      extractedText,
      summary,
      status: extractedText ? "ready" : source.status || prepared.status || current.status || "failed",
      statusMessage: extractedText
        ? source.statusMessage || prepared.statusMessage || current.statusMessage || "Source reader finished."
        : "No readable content was extracted.",
      parserProvider: source.parserProvider || prepared.parserProvider || current.parserProvider || "unknown",
      metadataProvider: geminiMetadata.title
        ? "gemini-ai-agent-title"
        : groqMetadata.title
          ? "groq-ai-agent-title"
          : "fallback-title",
      extractionLength: extractedText.length,
    },
  },
];
